import dd from 'dingtalk-jsapi';
import { action, observable, runInAction } from 'mobx';
import { IResponse, get, post } from '@/utils/request';
import { setCookie, getCookie, setLocal, getLocal } from '@/utils/method';
import { LOCAL_STORAGE, COOKIE } from '@/utils/constant';
import { notification } from 'antd';

const serverUrl = APP_CONFIG.APP_SERVICE;

export class UserStore {
    @observable
    ifLogin = false; // 登录状态

    @observable
    loginInfo = {}; // 登录成功返回的信息

    /**
     * 登录
     */
    @action
    login = async (dingUserId?: string): Promise<IResponse> => {
        try {
            const CLIENT = 'kanban';
            const result = await post(`${serverUrl}auth/dingUser/login`, {
                client: CLIENT,
                dingUserId
            });
            result &&
                result.data &&
                runInAction(() => {
                    const { jsessionid = '', name = '' } = result.data;
                    setCookie(COOKIE.JESSION_ID, jsessionid);
                    setLocal(LOCAL_STORAGE.MAPIC_USER_INFO, result.data);
                    setLocal(LOCAL_STORAGE.MAPIC_USER_NAME, name);
                    this.loginInfo = result.data;
                    this.ifLogin = true;
                });
            return result;
        } catch (e) {
            return e;
        }
    };

    /**
     * 初始加载项目，更新登录信息
     */
    @action
    initLoginInfo = () => {
        // setLocal(LOCAL_STORAGE.DING_ID, '01290319604408');
        this.ifLogin = Boolean(getCookie(COOKIE.JESSION_ID));
        this.loginInfo = getLocal(LOCAL_STORAGE.MAPIC_USER_INFO);
    };

    /**
     * 获取钉钉鉴权配置
     * @return void
     */
    @action
    getDingConfig = async () => {
        try {
            const result = await get(`${APP_CONFIG.DING_SIGNATURE_API}`, {
                url: window.encodeURIComponent(window.location.href)
            });
            result &&
                result.data &&
                runInAction(() => {
                    const { corpid, timestamp, noncestr, signature } = result.data;
                    dd.config({
                        agentId: APP_CONFIG.PARTNER_APP, // 微应用ID
                        corpId: corpid, // 企业ID
                        timeStamp: timestamp, // 生成签名的时间戳
                        nonceStr: noncestr, // 生成签名的随机串
                        signature: signature, // 签名
                        jsApiList: [
                            'biz.user.get',
                            'biz.navigation.setTitle',
                            'biz.util.openLocalFile',
                            'biz.util.uploadImage',
                            'biz.util.previewImage',
                            'device.geolocation.get',
                            'biz.map.locate',
                            'biz.map.view',
                            'biz.contact.choose',
                            'biz.chat.pickConversation',
                            'biz.ding.create',
                            'biz.ding.post',
                            'biz.contact.complexPicker',
                            'device.notification.alert',
                            'device.notification.confirm'
                        ]
                    });
                    dd.error(function(err) {
                        console.log('dd error: ' + JSON.stringify(err));
                        notification.error({
                            description: '获取用户信息失败ready',
                            message: '获取用户信息失败ready'
                        });
                    });
                });
            return result;
        } catch (e) {
            return e;
        }
    };

    /**
     * 获取钉钉用户信息
     * @return {Promise}
     */
    getDingUserInfo = (): Promise<string> => {
        try {
            return new Promise((res, rej) => {
                dd.ready(() => {
                    dd.biz.user.get({
                        onSuccess: info => {
                            console.log('userGet success: ' + JSON.stringify(info));
                            setLocal(LOCAL_STORAGE.DING_ID, info.emplId);
                            setLocal(LOCAL_STORAGE.DING_NAME, info.nickName);
                            res(info.emplId);
                        },
                        onFail: err => {
                            console.log('dd error: ' + JSON.stringify(err));
                            notification.error({
                                description: '获取用户信息失败user',
                                message: '获取用户信息失败'
                            });
                            rej();
                        }
                    });
                });
            });
        } catch (e) {
            return e;
        }
    };
}

const userStore = new UserStore();
export default userStore;
