/**
 * 修改交给 react-dom 渲染时的根组件。
 * 比如用于在外面包一个 Provider，
 * @param container
 */
export function rootContainer(container: React.ReactNode) {
    // 包装 mobx 的 Provider
    // const providerDom = <Provider {...store}>{container}</Provider>;
    const providerDom = (
        <ErrorBoundary>
            <Provider {...store}>{container}</Provider>
        </ErrorBoundary>
    );
    return providerDom;
}
/**
 * 路由变化处理
 * @param {*} { location, routes, action }
 */
export function onRouteChange({ location }: { location: Record<string, string> }) {
    const { setMenu, setTitle, closeLoading } = store.uiStore;
    closeLoading(); // 路由切换，将loading状态关闭
    // 设置菜单选中项和header标题
    if (location.pathname === '/') {
        // 如果是根路由，直接设置菜单选中1
        setMenu(Routes[0].routes[0].key);
        setTitle(Routes[0].routes[0].title);
        return;
    }
    const regStr = new RegExp('\\' + location.pathname + '(\\/|$)');
    const result: IRouteItem[] = Routes[0].routes.filter(item => {
        // 查找path匹配的路由配置，且排除根路由
        return item.path !== '/' && regStr.test(item.path);
    });
    if (result.length === 0) {
        // 无效路由设置
        setMenu('0');
        setTitle('未找到页面');
    } else {
        // 有效路由设置
        setMenu(result[0].key || '1');
        setTitle(result[0].title || '');
    }
}
